# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)

# Configuration
SECRET_KEY = os.environ.get('SECRET_KEY', secrets.token_hex(32))
JWT_EXPIRATION_HOURS = 24

# In-memory storage for nonces (use Redis or database in production)
nonce_store = {}

# Cleanup old nonces periodically
def cleanup_old_nonces():
    current_time = time.time()
    expired_nonces = [addr for addr, data in nonce_store.items() 
                      if current_time - data['timestamp'] > 300]  # 5 minutes
    for addr in expired_nonces:
        del nonce_store[addr]

@app.route('/auth/nonce', methods=['POST'])
def get_nonce():
    """
    Generate a nonce for wallet authentication
    Request: {"address": "0x..."}
    Response: {"nonce": "random_string"}
    """
    cleanup_old_nonces()
    
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address
    address = Web3.to_checksum_address(address)
    
    # Generate nonce
    nonce = secrets.token_hex(32)
    
    # Store nonce with timestamp
    nonce_store[address] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    return jsonify({
        'nonce': nonce,
        'message': f'Sign this message to authenticate with our platform.\n\nNonce: {nonce}\nTimestamp: {datetime.utcnow().isoformat()}'
    }), 200

@app.route('/auth/verify', places=['POST'])
def verify_signature():
    """
    Verify wallet signature and return JWT token
    Request: {
        "address": "0x...",
        "signature": "0x...",
        "message": "message_that_was_signed"
    }
    Response: {"token": "jwt_token", "address": "0x..."}
    """
    cleanup_old_nonces()
    
    data = request.get_json()
    
    if not data or not all(k in data for k in ['address', 'signature', 'message']):
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address
    address = Web3.to_checksum_address(address)
    
    # Check if nonce exists for this address
    if address not in nonce_store:
        return jsonify({'error': 'No nonce found. Request a nonce first'}), 400
    
    stored_nonce = nonce_store[address]['nonce']
    nonce_timestamp = nonce_store[address]['timestamp']
    
    # Check if nonce has expired (5 minutes)
    if time.time() - nonce_timestamp > 300:
        del nonce_store[address]
        return jsonify({'error': 'Nonce expired. Request a new nonce'}), 400
    
    # Verify that the message contains the stored nonce
    if stored_nonce not in message:
        return jsonify({'error': 'Invalid message. Message must contain the nonce'}), 400
    
    try:
        # Encode the message
        encoded_message = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = Web3().eth.account.recover_message(
            encoded_message,
            signature=signature
        )
        
        # Normalize recovered address
        recovered_address = Web3.to_checksum_address(recovered_address)
        
        # Verify that recovered address matches claimed address
        if recovered_address != address:
            return jsonify({'error': 'Signature verification failed'}), 401
        
        # Delete used nonce
        del nonce_store[address]
        
        # Generate JWT token
        token_payload = {
            'address': address,
            'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS),
            'iat': datetime.utcnow()
        }
        
        token = jwt.encode(token_payload, SECRET_KEY, algorithm='HS256')
        
        return jsonify({
            'token': token,
            'address': address,
            'expiresIn': JWT_EXPIRATION_HOURS * 3600
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Signature verification failed: {str(e)}'}), 401

@app.route('/auth/validate', methods=['POST'])
def validate_token():
    """
    Validate JWT token
    Request: {"token": "jwt_token"} or Authorization header
    Response: {"valid": true, "address": "0x..."}
    """
    token = None
    
    # Check Authorization header
    auth_header = request.headers.get('Authorization')
    if auth_header and auth_header.startswith('Bearer '):
        token = auth_header.split(' ')[1]
    else:
        # Check request body
        data = request.get_json()
        if data and 'token' in data:
            token = data['token']
    
    if not token:
        return jsonify({'error': 'Token is required'}), 400
    
    try:
        # Decode and verify token
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        
        return jsonify({
            'valid': True,
            'address': payload['address'],
            'expiresAt': payload['exp']
        }), 200
        
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired', 'valid': False}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token', 'valid': False}), 401

def require_auth(f):
    """
    Decorator to protect routes with JWT authentication
    """
    from functools import wraps
    
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = None
        auth_header = request.headers.get('Authorization')
        
        if auth_header and auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
        
        if not token:
            return jsonify({'error': 'Authentication required'}), 401
        
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            request.user_address = payload['address']
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        
        return f(*args, **kwargs)
    
    return decorated_function

@app.route('/protected', methods=['GET'])
@require_auth
def protected_route():
    """
    Example protected route
    """
    return jsonify({
        'message': 'Access granted',
        'address': request.user_address
    }), 200

@app.route('/health', methods=['GET'])
def health_check():
    """
    Health check endpoint
    """
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)